"use strict";(globalThis.webpackChunkstorm_docs=globalThis.webpackChunkstorm_docs||[]).push([[5820],{2583(e){e.exports=JSON.parse('{"version":{"pluginId":"default","version":"1.9.0","label":"1.9.0","banner":"unmaintained","badge":true,"noIndex":false,"className":"docs-version-1.9.0","isLast":false,"docsSidebars":{"docs":[{"type":"link","href":"/1.9.0/","label":"Introduction","docId":"index","unlisted":false},{"type":"category","label":"Core Concepts","items":[{"type":"link","href":"/1.9.0/getting-started","label":"Getting Started","docId":"getting-started","unlisted":false},{"type":"link","href":"/1.9.0/entities","label":"Entities","docId":"entities","unlisted":false},{"type":"link","href":"/1.9.0/projections","label":"Projections","docId":"projections","unlisted":false},{"type":"link","href":"/1.9.0/relationships","label":"Relationships","docId":"relationships","unlisted":false},{"type":"link","href":"/1.9.0/repositories","label":"Repositories","docId":"repositories","unlisted":false},{"type":"link","href":"/1.9.0/queries","label":"Queries","docId":"queries","unlisted":false},{"type":"link","href":"/1.9.0/metamodel","label":"Static Metamodel","docId":"metamodel","unlisted":false},{"type":"link","href":"/1.9.0/refs","label":"Refs","docId":"refs","unlisted":false},{"type":"link","href":"/1.9.0/transactions","label":"Transactions","docId":"transactions","unlisted":false},{"type":"link","href":"/1.9.0/spring-integration","label":"Spring Integration","docId":"spring-integration","unlisted":false},{"type":"link","href":"/1.9.0/dialects","label":"Database Dialects","docId":"dialects","unlisted":false},{"type":"link","href":"/1.9.0/testing","label":"Testing","docId":"testing","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Advanced Topics","items":[{"type":"category","label":"Entity Modeling","items":[{"type":"link","href":"/1.9.0/polymorphism","label":"Polymorphism","docId":"polymorphism","unlisted":false},{"type":"link","href":"/1.9.0/converters","label":"Converters","docId":"converters","unlisted":false},{"type":"link","href":"/1.9.0/entity-lifecycle","label":"Entity Lifecycle","docId":"entity-lifecycle","unlisted":false},{"type":"link","href":"/1.9.0/validation","label":"Validation","docId":"validation","unlisted":false},{"type":"link","href":"/1.9.0/json","label":"JSON Support","docId":"json","unlisted":false},{"type":"link","href":"/1.9.0/serialization","label":"Entity Serialization","docId":"serialization","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Operations","items":[{"type":"link","href":"/1.9.0/batch-streaming","label":"Batch Processing & Streaming","docId":"batch-streaming","unlisted":false},{"type":"link","href":"/1.9.0/upserts","label":"Upserts","docId":"upserts","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Internals","items":[{"type":"link","href":"/1.9.0/sql-templates","label":"SQL Templates","docId":"sql-templates","unlisted":false},{"type":"link","href":"/1.9.0/hydration","label":"Hydration","docId":"hydration","unlisted":false},{"type":"link","href":"/1.9.0/dirty-checking","label":"Dirty Checking","docId":"dirty-checking","unlisted":false},{"type":"link","href":"/1.9.0/entity-cache","label":"Entity Cache","docId":"entity-cache","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"Operational","items":[{"type":"link","href":"/1.9.0/configuration","label":"Configuration","docId":"configuration","unlisted":false},{"type":"link","href":"/1.9.0/sql-logging","label":"SQL Logging","docId":"sql-logging","unlisted":false},{"type":"link","href":"/1.9.0/metrics","label":"Metrics","docId":"metrics","unlisted":false}],"collapsed":true,"collapsible":true}],"collapsed":true,"collapsible":true},{"type":"category","label":"Resources","items":[{"type":"link","href":"/1.9.0/comparison","label":"Storm vs Other Frameworks","docId":"comparison","unlisted":false},{"type":"link","href":"/1.9.0/faq","label":"Frequently Asked Questions","docId":"faq","unlisted":false},{"type":"link","href":"/1.9.0/migration-from-jpa","label":"Migration from JPA","docId":"migration-from-jpa","unlisted":false}],"collapsed":true,"collapsible":true},{"type":"category","label":"API Reference","items":[{"type":"link","href":"/1.9.0/api-kotlin","label":"Kotlin API Reference","docId":"api-kotlin","unlisted":false},{"type":"link","href":"/1.9.0/api-java","label":"Java API Reference","docId":"api-java","unlisted":false}],"collapsed":true,"collapsible":true}]},"docs":{"api-java":{"id":"api-java","title":"Java API Reference","description":"Storm\'s Java API is organized into a set of focused modules. Each module has a specific role, from the core ORM engine to Spring Boot auto-configuration. This page provides an overview of the module structure and links to detailed documentation for each concept.","sidebar":"docs"},"api-kotlin":{"id":"api-kotlin","title":"Kotlin API Reference","description":"Storm\'s Kotlin API is organized into a set of focused modules. Each module has a specific role, from the core ORM engine with coroutine support to Spring Boot auto-configuration and validation. This page provides an overview of the module structure and links to detailed documentation for each concept.","sidebar":"docs"},"batch-streaming":{"id":"batch-streaming","title":"Batch Processing & Streaming","description":"Database performance often degrades when applications issue many individual SQL statements in a loop. Each statement incurs network latency, server-side parsing, and transaction log overhead. Batch processing and streaming solve two sides of this problem: batch processing reduces the cost of writing many rows, and streaming reduces the memory cost of reading many rows.","sidebar":"docs"},"common-patterns":{"id":"common-patterns","title":"Common Patterns","description":"This page collects practical patterns for recurring requirements that are not covered by a dedicated Storm API but are straightforward to implement using the framework\'s building blocks. Each pattern includes a complete example with the entity definition, supporting code, and usage."},"comparison":{"id":"comparison","title":"Storm vs Other Frameworks","description":"There is no universally \\"best\\" database framework. Each has strengths suited to different situations, team preferences, and project requirements. Teams approach data access differently, including using frameworks at various abstraction levels or even plain SQL. This page provides a comparison to help you evaluate whether Storm fits your needs, particularly if you value explicit and predictable behavior and fast development. We encourage you to explore the linked documentation for each framework and form your own conclusions.","sidebar":"docs"},"configuration":{"id":"configuration","title":"Configuration","description":"Storm can be configured through StormConfig, system properties, or Spring Boot\'s application.yml. These properties control runtime behavior for features like dirty checking and entity caching. All properties have sensible defaults, so configuration is optional. Storm works out of the box without any configuration.","sidebar":"docs"},"converters":{"id":"converters","title":"Converters","description":"Storm maps record components to database columns using built-in type support for standard Java and JDBC types. When your entity contains a type that is not directly supported by the JDBC driver, or when you want a custom mapping between your domain model and the database, you need a converter.","sidebar":"docs"},"dialects":{"id":"dialects","title":"Database Dialects","description":"Storm works with any JDBC-compatible database using standard SQL. However, databases diverge on features like upserts, pagination, JSON handling, and native data types. Dialect packages let Storm take advantage of these database-specific capabilities while keeping your application code portable. Your entities, repositories, and queries stay the same regardless of which database you use; only the dialect dependency changes.","sidebar":"docs"},"dirty-checking":{"id":"dirty-checking","title":"Dirty Checking","description":"What Is Dirty Checking?","sidebar":"docs"},"entities":{"id":"entities","title":"Entities","description":"Storm entities are simple data classes that map to database tables. By default, Storm applies sensible naming conventions to map entity fields to database columns automatically.","sidebar":"docs"},"entity-cache":{"id":"entity-cache","title":"Entity Cache","description":"Storm maintains a transaction-scoped entity cache that optimizes database interactions. The cache is a pure performance optimization: it never changes the semantics of your transactions. What you read from the database is exactly what you would read without caching; the cache simply avoids redundant work.","sidebar":"docs"},"entity-lifecycle":{"id":"entity-lifecycle","title":"Entity Lifecycle","description":"Storm provides a typed EntityCallback interface that lets you hook into entity lifecycle events. Callbacks are a general-purpose building block for cross-cutting concerns like auditing, validation, and logging, while keeping Storm unopinionated about how those concerns are implemented.","sidebar":"docs"},"error-handling":{"id":"error-handling","title":"Error Handling","description":"When something goes wrong, Storm communicates the problem through a small, well-defined set of exception types. Understanding which exceptions can be thrown and when helps you write robust error handling that distinguishes between recoverable situations (like a missing entity) and programming mistakes (like a schema mismatch)."},"faq":{"id":"faq","title":"Frequently Asked Questions","description":"General","sidebar":"docs"},"first-entity":{"id":"first-entity","title":"First Entity","description":"This guide walks you through defining your first Storm entity, creating an ORM template, and performing basic CRUD operations. By the end, you will have inserted a record into the database and read it back."},"first-query":{"id":"first-query","title":"First Query","description":"Once you can insert and fetch records (see First Entity), the next step is querying. This page covers the query patterns you will use most often: filtering with predicates, using repositories, streaming results, and writing type-safe queries with the metamodel."},"getting-started":{"id":"getting-started","title":"Getting Started","description":"Storm is a modern SQL Template and ORM framework for Kotlin 2.0+ and Java 21+. It uses immutable data classes and records instead of proxied entities, giving you predictable behavior, type-safe queries, and high performance.","sidebar":"docs"},"glossary":{"id":"glossary","title":"Glossary","description":"This page defines key terms used throughout the Storm documentation."},"hydration":{"id":"hydration","title":"Hydration","description":"Hydration is the process of transforming flat database rows into structured Kotlin data classes and Java records.","sidebar":"docs"},"index":{"id":"index","title":"Introduction","description":"Storm is a modern, high-performance ORM for Kotlin 2.0+ and Java 21+, built around a powerful SQL template engine. It focuses on simplicity, type safety, and predictable performance through immutable models and compile-time metadata.","sidebar":"docs"},"installation":{"id":"installation","title":"Installation","description":"This page covers everything you need to add Storm to your project: prerequisites, dependency setup, and optional modules."},"json":{"id":"json","title":"JSON Support","description":"Storm provides first-class support for JSON columns, allowing you to store and query JSON data directly in your entities. Annotate a field with @Json and Storm handles serialization/deserialization automatically.","sidebar":"docs"},"metamodel":{"id":"metamodel","title":"Static Metamodel","description":"The static metamodel is a code generation feature that creates companion classes for your entities at compile time. These generated classes provide type-safe references to entity fields, enabling the compiler to catch errors that would otherwise surface only at runtime.","sidebar":"docs"},"metrics":{"id":"metrics","title":"Metrics","description":"Storm exposes runtime metrics through JMX (Java Management Extensions) MBeans. These metrics give you visibility into template compilation performance, dirty checking behavior, and entity cache efficiency. All MBeans are registered automatically when Storm initializes and aggregate across all ORMTemplate instances in the JVM.","sidebar":"docs"},"migration-from-jpa":{"id":"migration-from-jpa","title":"Migration from JPA","description":"This guide helps you transition from JPA/Hibernate to Storm. The two frameworks can coexist in the same application, allowing you to migrate gradually, one entity or repository at a time.","sidebar":"docs"},"performance":{"id":"performance","title":"Performance","description":"Storm is designed to add minimal overhead on top of JDBC. In most applications, the bottleneck is the database itself, not the ORM layer. Still, understanding how Storm processes queries, caches compiled templates, and manages entity state helps you make informed decisions about configuration and optimization."},"polymorphism":{"id":"polymorphism","title":"Polymorphism","description":"Storm supports polymorphic entity hierarchies using sealed types. Instead of the proxy-based inheritance strategies found in traditional ORMs, Storm leverages sealed interfaces and data classes (Kotlin) or records (Java) to provide compile-time type safety with exhaustive pattern matching. The sealed type hierarchy tells the compiler exactly which subtypes exist, so a when (Kotlin) or switch (Java) expression over a polymorphic result is guaranteed to cover all cases.","sidebar":"docs"},"projections":{"id":"projections","title":"Projections","description":"What Are Projections?","sidebar":"docs"},"queries":{"id":"queries","title":"Queries","description":"Storm provides a powerful and flexible query API. All queries are type-safe; the generated metamodel (User, City, etc.) catches errors at compile time rather than at runtime.","sidebar":"docs"},"refs":{"id":"refs","title":"Refs","description":"Refs are lightweight identifiers for entities, projections, and other data types that defer fetching until explicitly required. They optimize performance by avoiding unnecessary data retrieval and are useful for managing large object graphs.","sidebar":"docs"},"relationships":{"id":"relationships","title":"Relationships","description":"Automatic relationship loading is a core part of Storm\'s design. Your data model is fully captured by immutable entity classes. When you define a foreign key, Storm automatically joins the related entity and returns complete, fully populated records in a single query.","sidebar":"docs"},"repositories":{"id":"repositories","title":"Repositories","description":"Entity repositories provide a high-level abstraction for managing entities in the database. They offer methods for creating, reading, updating, and deleting entities, as well as querying and filtering based on specific criteria.","sidebar":"docs"},"security":{"id":"security","title":"Security","description":"Storm is designed with security as a structural property rather than an afterthought. The framework\'s template-based query model makes SQL injection difficult by construction, and its stateless entity design reduces the surface area for common ORM-related vulnerabilities."},"serialization":{"id":"serialization","title":"Entity Serialization","description":"Storm entities are plain records and data classes. Because they carry no proxies, no hidden state, and no framework-managed lifecycle, they serialize naturally with standard JSON libraries. An entity that contains only primitive fields, standard types like LocalDate, and inline @FK relationships will work out of the box with Jackson or kotlinx.serialization, with no additional configuration required.","sidebar":"docs"},"spring-integration":{"id":"spring-integration","title":"Spring Integration","description":"Storm integrates seamlessly with Spring Framework and Spring Boot for dependency injection, transaction management, and repository auto-wiring. This guide covers setup for both languages.","sidebar":"docs"},"sql-logging":{"id":"sql-logging","title":"SQL Logging","description":"When debugging performance issues or tracing application behavior, you often need visibility into the SQL statements your ORM generates. Standard JDBC logging shows raw statements with ? placeholders, giving you no context about which repository method triggered the query or what the actual parameter values were.","sidebar":"docs"},"sql-templates":{"id":"sql-templates","title":"SQL Templates","description":"SQL templates are the foundation of Storm. The EntityRepository and ProjectionRepository APIs are built entirely on top of SQL templates. Everything those repositories do, such as generating SELECT columns, deriving joins from @FK relationships, and resolving table aliases, uses the same template engine available to you directly.","sidebar":"docs"},"testing":{"id":"testing","title":"Testing","description":"Writing tests for database code can involve repetitive setup: creating a DataSource, running schema scripts, obtaining an ORMTemplate, and wiring everything together before the first assertion. Storm\'s test support module reduces this to a single annotation, letting you focus on the behavior you are testing rather than infrastructure.","sidebar":"docs"},"transactions":{"id":"transactions","title":"Transactions","description":"Transaction management is fundamental to database programming. Storm takes a practical approach: rather than inventing new abstractions, it provides first-class support for standard transaction semantics while integrating seamlessly with your existing infrastructure.","sidebar":"docs"},"upserts":{"id":"upserts","title":"Upserts","description":"Many applications need to create a record if it does not exist, or update it if it does. A naive approach using separate SELECT-then-INSERT-or-UPDATE logic introduces race conditions: two concurrent requests can both see that a row is missing and both attempt to insert, causing a constraint violation. Even with application-level locking, this approach adds complexity and reduces throughput.","sidebar":"docs"},"validation":{"id":"validation","title":"Validation","description":"Storm validates your entity and projection definitions at two levels: structural validation ensures your records follow the ORM\'s rules (valid primary key types, correct use of annotations, no circular dependencies), while schema validation compares your definitions against the actual database to catch mismatches before they surface as runtime errors.","sidebar":"docs"}}}}')}}]);